#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 3e5+5;
const int K = (N<<5);
int n,m,Q,p[N],a[N];
int node_cnt,Rt[N],ls[K],rs[K],sum[K];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void build(int &u,int l,int r){
    u=(++node_cnt);//动态开点
    if(l==r)return;//叶子
    int mid=(l+r)>>1;//取中间值切半
    build(ls[u],l,mid);//左儿子
    build(rs[u],mid+1,r);//右儿子
    return;//处理完毕
}
int update(int u,int l,int r,int k){
    int v=(++node_cnt);//开新点
    ls[v]=ls[u],rs[v]=rs[u];sum[v]=sum[u]+1;//更新值
    if(l==r)return v;//叶子
    int mid=(l+r)>>1;//取中间值切半
    if(k<=mid)ls[v]=update(ls[v],l,mid,k);//左儿子
    else rs[v]=update(rs[v],mid+1,r,k);//右儿子
    return v;//处理完毕
}
int query(int u,int v,int l,int r,int k){
    int mid=((l+r)>>1);//取中间值切半
    int x=sum[ls[v]]-sum[ls[u]];//方向判断
    if(l==r)return l;//叶子
    if(x>=k)return query(ls[u],ls[v],l,mid,k);//往左跑
    else return query(rs[u],rs[v],mid+1,r,k-x);//往右跑
}
int main(){
    n=read(),Q=read();//读入
    for(int i=1;i<=n;i++)p[i]=read(),a[i]=p[i];//读入
    sort(a+1,a+n+1);//排序
    m=unique(a+1,a+n+1)-a-1;//去重
    build(Rt[0],1,m);//建树
    for(int i=1;i<=n;i++){
        int tmp=lower_bound(a+1,a+m+1,p[i])-a;
        Rt[i]=update(Rt[i-1],1,m,tmp);
    }//预处理点修改
    while(Q--){//处理查询
        int l=read(),r=read(),k=read();//读入
        int id=query(Rt[l-1],Rt[r],1,m,k);//查询
        cout<<a[id]<<"\n";//输出
    }
    return 0;
}
